// OJ-Assessment-SLA-Monitor (OJ-FUNNEL B2, 2026-07-19)
// Emits sla_status rows into outcome_attribution for every assessment row updated in the last
// 96h. Buckets: on_track (<=48h and delivered), sla_breach (>48h since paid and NOT delivered),
// stuck_no_transcript / stuck_failed / stuck_report_generated (needs resend key -> handoff).
// Idempotency: one sla row per assessment id per bucket (via notes JSON prefix).
const OJ_URL='https://wwacjhkpuaiijbkqnhsi.supabase.co';
const OJ_KEY='eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Ind3YWNqaGtwdWFpaWpia3FuaHNpIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3ODgwODQyNSwiZXhwIjoyMDk0Mzg0NDI1fQ.I92OcFBQ9lxs4hFH3Q_rWYup2bULHuL3a2rqeEb1xf0';
const H={apikey:OJ_KEY,Authorization:'Bearer '+OJ_KEY,'Content-Type':'application/json'};
async function get(p){return await this.helpers.httpRequest({method:'GET',url:OJ_URL+'/rest/v1/'+p,headers:H,json:true});}
async function post(p,body){return await this.helpers.httpRequest({method:'POST',url:OJ_URL+'/rest/v1/'+p,headers:{...H,Prefer:'return=minimal'},body,json:true});}
const now=Date.now();
const cutoffIso=new Date(now-96*3600*1000).toISOString();
const a=await get.call(this,'assessments?select=id,prospect_id,created_at,updated_at,status,report_url&updated_at=gt.'+cutoffIso+'&limit=200');
const already=await get.call(this,'outcome_attribution?select=notes&outcome_type=like.assessment_sla_*&created_at=gt.'+cutoffIso+'&limit=500');
const seen=new Set(already.map(x=>{try{return JSON.parse(x.notes||'{}').aid;}catch(e){return null;}}).filter(Boolean));
const out={on_track:0,sla_breach:0,stuck_no_transcript:0,stuck_failed:0,stuck_report_generated:0,skipped:0};
for(const r of a){
  if(seen.has(r.id)){out.skipped++;continue;}
  const ageH=(now-Date.parse(r.created_at))/3600000;
  let bucket=null;
  if(r.status==='delivered') bucket=ageH<=48?'on_track':'sla_breach_delivered_late';
  else if(r.status==='no_transcript') bucket='stuck_no_transcript';
  else if(r.status==='failed') bucket='stuck_failed';
  else if(r.status==='report_generated' && ageH>2) bucket='stuck_report_generated';
  else if((r.status==='processing'||r.status==='pending') && ageH>48) bucket='sla_breach_processing';
  else{out.skipped++;continue;}
  await post.call(this,'outcome_attribution',{company_id:'opsjuice',outcome_type:'assessment_sla_'+bucket,prospect_id:r.prospect_id,
    notes:JSON.stringify({aid:r.id,status:r.status,age_h:Math.round(ageH),report_url:!!r.report_url})});
  out[bucket]=(out[bucket]||0)+1;
}
return [{json:out}];
